VALUES
  ('real-estate-moex-02942', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙共同毆傷丙，經法院判決甲、乙須連帶負 100 萬元之損害賠償，事後甲、乙間約定各自負擔一半 之責任，但丙卻對甲請求給付80萬元之賠償，甲有何權利可主張：', '["超過50萬元部分拒絕給付", "就80萬元部分負擔一半之責任", "全部拒絕賠償", "甲無權拒絕丙之請求"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02943', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '土地及其土地上之建築物，同屬於一人所有，而僅以建築物為抵押者，於抵押物拍賣時，拍定人與土地 所有權人間之關係為：', '["拍定人視為取得抵押權", "拍定人視為取得租賃權", "拍定人視為取得使用借貨權", "拍定人視為取得地上權"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02944', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲向乙購買房屋一間，雙方約定房屋過戶後次日甲應給付剩餘款項，但甲並未依約付款，乙得如何主張 其權利：', '["立刻解除契約", "終止契約", "定期催告", "撤銷契約"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02945', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '債權人受領他種給付以代原定給付者，其債之關係消滅，此種情形稱為：', '["間接給付", "代位求償", "代替給付", "代物清償"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02946', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲積欠乙之貨款，遂以自己所開立之銀行支票對乙為清償，此種情形通稱為：', '["代物清償", "代位求償", "新債清償", "代替給付"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
