  ('real-estate-moex-02948', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '買受人發現物有瑕疵，而通知出賣人者，最遲應於何時主張物之瑕疵擔保責任：', '["通知後3個月內", "通知後6個月內", "通知後1年內", "通知後2年內"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
